tasks.solution:
#include <iostream>

int main() {
    int start, end;
    if (!(std::cin >> start >> end)) {
        return 0;
    }

    long long sum = 0;

    for (int i = start; i <= end; ++i) {
        if (i % 2 != 0) {
            sum += i;
        }
    }

    std::cout << sum << std::endl;

    return 0;
}
